return items.map((item) => {
  const j = item.json;

  const clean = (s) =>
    String(s || "")
      .replace(/[\s\u200B-\u200D\uFEFF]/g, "")
      .toLowerCase();

  const findValue = (keywordGroups, fallback = "-") => {
    const keys = Object.keys(j);
    for (const key of keys) {
      const ck = clean(key);
      const matched = keywordGroups.some((group) =>
        group.every((kw) => ck.includes(clean(kw)))
      );
      if (matched) {
        const v = j[key];
        if (v !== undefined && v !== null && String(v).trim() !== "") {
          return String(v).trim();
        }
      }
    }
    return fallback;
  };

  const fullname = findValue([["ชื่อ"], ["นามสกุล"]], "-");
  const company = findValue([["บริษัท"], ["หน่วยงาน"]], "-");
  const phone = findValue([["เบอร์", "โทร"], ["โทรศัพท์"], ["เบอร์โทร"]], "-");
  const itemName = findValue([["รายชื่อ", "อุปกรณ์"], ["อุปกรณ์"]], "-");
  const quantity = findValue([["จำนวน", "เบิก"], ["จำนวน"]], "-");
  const emailUser = findValue([["email"], ["อีเมล"]], "-");
  const reason = findValue([["เหตุผล", "เบิก"], ["เหตุผล"]], "-");

  let requestDate = findValue([["ประทับเวลา"], ["วันที่"], ["timestamp"]], "-");
  const serial = Number(requestDate);
  if (!Number.isNaN(serial) && serial > 1000) {
    const excelEpoch = new Date(1899, 11, 30);
    const dt = new Date(excelEpoch.getTime() + serial * 86400000);
    requestDate = dt.toLocaleString("th-TH");
  }

  const status = findValue([["สถานะ", "คำขอ"], ["สถานะ"]], "รออนุมัติ");

  j.mailToAdmin = "sakkarat.tai@gmail.com"; // เปลี่ยนเป็นเมลแอดมินจริงได้
  j.mailSubjectAdmin = "มีคำขอเบิกใหม่ รออนุมัติ";
  j.mailBodyAdmin =
`มีคำขอเบิกใหม่เข้าระบบ

วันที่: ${requestDate}
ชื่อ-นามสกุล: ${fullname}
บริษัท/หน่วยงาน: ${company}
เบอร์โทร: ${phone}
รายการอุปกรณ์: ${itemName}
จำนวนที่เบิก: ${quantity}
อีเมลผู้ขอ: ${emailUser}
เหตุผลการเบิก: ${reason}
สถานะคำขอ: ${status}

กรุณาเข้าเว็บ Admin เพื่ออนุมัติ`;

  return item;
});

